    email: sanitizeString(payload.email),
    emailVerified: typeof payload.email_verified === 'boolean' ? payload.email_verified : false,
    picture: sanitizeUrl(payload.picture),
    givenName: sanitizeString(payload.given_name),
    familyName: sanitizeString(payload.family_name),
