// src/App.js
import React, { useState, useEffect, useCallback } from 'react';
import { AuthProvider, useAuth } from './AuthContext';
import LoginPage from './components/LoginPage';
import CallbackPage from './components/CallbackPage';
import Dashboard from './components/Dashboard';
import ErrorPage from './components/ErrorPage';

function AppContent() {
  const { authenticated, loading, error } = useAuth();
  const [currentPath, setCurrentPath] = useState(window.location.pathname);
  const [authError, setAuthError] = useState(null);

  useEffect(() => {
    const handlePopState = () => {
      setCurrentPath(window.location.pathname);
    };
    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  const handleCallbackSuccess = useCallback(() => {
    setCurrentPath('/');
    window.history.replaceState({}, document.title, '/');
  }, []);

  const handleCallbackError = useCallback((err) => {
    setAuthError(err.message);
  }, []);

  const handleRetry = useCallback(() => {
    setAuthError(null);
    setCurrentPath('/');
    window.history.replaceState({}, document.title, '/');
  }, []);

  // Add CSS animation for spinner
  useEffect(() => {
    const style = document.createElement('style');
    style.textContent = `
      @keyframes spin {
        0% { transform: rotate(0deg); }
        100% { transform: rotate(360deg); }
      }
    `;
    document.head.appendChild(style);
    return () => document.head.removeChild(style);
  }, []);

  if (loading) {
    return (
      <div
        style={{
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          minHeight: '100vh',
          fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
        }}
      >
        <p>Loading...</p>
      </div>
    );
  }

  if (authError) {
    return <ErrorPage message={authError} onRetry={handleRetry} />;
  }

  if (error && currentPath !== '/callback') {
    return <ErrorPage message={error} onRetry={handleRetry} />;
  }

  // Handle callback route
  if (currentPath === '/callback') {
    return (
      <CallbackPage
        onSuccess={handleCallbackSuccess}
        onError={handleCallbackError}
      />
    );
  }

  // Show dashboard if authenticated, otherwise show login
  if (authenticated) {
    return <Dashboard />;
  }

  return <LoginPage />;
}

function App() {
  return (
    <AuthProvider>
      <AppContent />
    </AuthProvider>
  );
}

export default App;